selector_to_html = {"a[href=\"#gpg-agent-session-management\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">GPG agent session management<a class=\"headerlink\" href=\"#gpg-agent-session-management\" title=\"Link to this heading\">\u00b6</a></h3><p>The agent caches your passphrase for the duration of a session. To extend the cache lifetime:</p>", "a[href=\"#reboot-behaviour\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Reboot behaviour<a class=\"headerlink\" href=\"#reboot-behaviour\" title=\"Link to this heading\">\u00b6</a></h3><p>The tmpfs at is cleared on reboot \u2014 this is intentional. After rebooting, run <code class=\"docutils literal notranslate\"><span class=\"pre\">./scripts/compose-wrapper.sh</span></code> as normal; it will re-create the tmpfs and decrypt fresh from the pass store.</p>", "a[href=\"#optionally-configure-passwordless-sudo-for-tmpfs\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">1.8 Optionally configure passwordless sudo for tmpfs<a class=\"headerlink\" href=\"#optionally-configure-passwordless-sudo-for-tmpfs\" title=\"Link to this heading\">\u00b6</a></h3><p>To avoid entering your sudo password on every startup, add a targeted sudoers rule:</p>", "a[href=\"#stopping-the-stack\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Stopping the stack<a class=\"headerlink\" href=\"#stopping-the-stack\" title=\"Link to this heading\">\u00b6</a></h3><p>Bring down the containers and wipe the tmpfs:</p>", "a[href=\"#rotating-a-password\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Rotating a password<a class=\"headerlink\" href=\"#rotating-a-password\" title=\"Link to this heading\">\u00b6</a></h3><p>After rotation, restart the affected service to pick up the new value:</p>", "a[href=\"#secrets-management-with-pass\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Secrets Management with <code class=\"docutils literal notranslate\"><span class=\"pre\">pass</span></code><a class=\"headerlink\" href=\"#secrets-management-with-pass\" title=\"Link to this heading\">\u00b6</a></h1><h2>Set up pass<a class=\"headerlink\" href=\"#set-up-pass\" title=\"Link to this heading\">\u00b6</a></h2><h3>1.1 Install dependencies<a class=\"headerlink\" href=\"#install-dependencies\" title=\"Link to this heading\">\u00b6</a></h3>", "a[href=\"#git-back-the-pass-store-recommended\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">1.7 Git-back the pass store (recommended)<a class=\"headerlink\" href=\"#git-back-the-pass-store-recommended\" title=\"Link to this heading\">\u00b6</a></h3><p>Every subsequent <code class=\"docutils literal notranslate\"><span class=\"pre\">pass</span> <span class=\"pre\">insert</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">pass</span> <span class=\"pre\">edit</span></code>, or <code class=\"docutils literal notranslate\"><span class=\"pre\">pass</span> <span class=\"pre\">rm</span></code> automatically commits. Push with <code class=\"docutils literal notranslate\"><span class=\"pre\">pass</span> <span class=\"pre\">git</span> <span class=\"pre\">push</span></code>.</p><p>Update <code class=\"docutils literal notranslate\"><span class=\"pre\">.gitignore</span></code>:</p>", "a[href=\"#set-up-pass\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Set up pass<a class=\"headerlink\" href=\"#set-up-pass\" title=\"Link to this heading\">\u00b6</a></h2><h3>1.1 Install dependencies<a class=\"headerlink\" href=\"#install-dependencies\" title=\"Link to this heading\">\u00b6</a></h3>", "a[href=\"#day-to-day-workflow\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Day-to-Day Workflow<a class=\"headerlink\" href=\"#day-to-day-workflow\" title=\"Link to this heading\">\u00b6</a></h2><h3>Starting the stack<a class=\"headerlink\" href=\"#starting-the-stack\" title=\"Link to this heading\">\u00b6</a></h3><p>The GPG agent prompts for your key passphrase on the first decryption after login. Subsequent runs within the same session are served from the agent cache without re-prompting.</p><p>The start script does not automatically wipe the tmpfs on exit. The tmpfs is wiped by <code class=\"docutils literal notranslate\"><span class=\"pre\">./scripts/compose-wrapper.sh</span> <span class=\"pre\">down</span></code> instead, or cleared automatically on reboot.</p>", "a[href=\"#configure-gpg-agent\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">1.3 Configure GPG agent<a class=\"headerlink\" href=\"#configure-gpg-agent\" title=\"Link to this heading\">\u00b6</a></h3><p>Ensure the agent can prompt for the passphrase in a terminal (required for SSH sessions and headless environments):</p>", "a[href=\"#install-dependencies\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">1.1 Install dependencies<a class=\"headerlink\" href=\"#install-dependencies\" title=\"Link to this heading\">\u00b6</a></h3>", "a[href=\"#generate-a-gpg-key\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">1.2 Generate a GPG key<a class=\"headerlink\" href=\"#generate-a-gpg-key\" title=\"Link to this heading\">\u00b6</a></h3><p>When prompted:</p>", "a[href=\"#viewing-secrets\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Viewing secrets<a class=\"headerlink\" href=\"#viewing-secrets\" title=\"Link to this heading\">\u00b6</a></h3>", "a[href=\"#back-up-the-gpg-private-key\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">1.6 Back up the GPG private key<a class=\"headerlink\" href=\"#back-up-the-gpg-private-key\" title=\"Link to this heading\">\u00b6</a></h3><p>Store the backup on an encrypted USB or in a separate password manager. Without this backup, the encrypted secrets are unrecoverable if the key is lost.</p>", "a[href=\"#starting-the-stack\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Starting the stack<a class=\"headerlink\" href=\"#starting-the-stack\" title=\"Link to this heading\">\u00b6</a></h3><p>The GPG agent prompts for your key passphrase on the first decryption after login. Subsequent runs within the same session are served from the agent cache without re-prompting.</p><p>The start script does not automatically wipe the tmpfs on exit. The tmpfs is wiped by <code class=\"docutils literal notranslate\"><span class=\"pre\">./scripts/compose-wrapper.sh</span> <span class=\"pre\">down</span></code> instead, or cleared automatically on reboot.</p>", "a[href=\"#removing-a-secret\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Removing a secret<a class=\"headerlink\" href=\"#removing-a-secret\" title=\"Link to this heading\">\u00b6</a></h3><p>Then remove the corresponding mount from <code class=\"docutils literal notranslate\"><span class=\"pre\">compose.yml</span></code> and the decryption line from <code class=\"docutils literal notranslate\"><span class=\"pre\">scripts/compose-wrapper.sh</span></code>.</p>", "a[href=\"#checking-what-s-exposed\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Checking what\u2019s exposed<a class=\"headerlink\" href=\"#checking-what-s-exposed\" title=\"Link to this heading\">\u00b6</a></h3><p>Verify nothing secret is in container environments:</p>", "a[href=\"#insert-secrets\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">1.5 Insert secrets<a class=\"headerlink\" href=\"#insert-secrets\" title=\"Link to this heading\">\u00b6</a></h3><p><strong>Passwords and passphrases</strong> are single-line values. Use <code class=\"docutils literal notranslate\"><span class=\"pre\">--echo</span></code> to insert them non-interactively:</p>", "a[href=\"#rotating-a-certificate-or-key\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Rotating a certificate or key<a class=\"headerlink\" href=\"#rotating-a-certificate-or-key\" title=\"Link to this heading\">\u00b6</a></h3><p>Use <code class=\"docutils literal notranslate\"><span class=\"pre\">--multiline</span></code> and redirect from the new file \u2014 never use <code class=\"docutils literal notranslate\"><span class=\"pre\">--echo</span></code> for PEM content:</p>", "a[href=\"#adding-a-new-secret\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Adding a new secret<a class=\"headerlink\" href=\"#adding-a-new-secret\" title=\"Link to this heading\">\u00b6</a></h3><p>Then:</p>", "a[href=\"#initialise-the-pass-store\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">1.4 Initialise the pass store<a class=\"headerlink\" href=\"#initialise-the-pass-store\" title=\"Link to this heading\">\u00b6</a></h3><p>This creates <code class=\"docutils literal notranslate\"><span class=\"pre\">~/.password-store/</span></code> and records which GPG key encrypts the store.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
